Here's how to structure your tests using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fail the test if it hangs
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("fast response", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass TestContext.CancellationToken for cooperative timeout
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast response", result);
    }

    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_SlowServer_TimeoutCancelsOperation()
    {
        // Arrange
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — CancellationToken fires when [Timeout] expires
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Test doubles ---

    private sealed class FakeHttpMessageHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayedHttpMessageHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken); // respects cancellation
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key takeaways:**

- **`TestContext.CancellationToken`** — always pass this to async calls in tests with `[Timeout]`. When the timeout expires, MSTest cancels this token, giving your code a chance to exit cooperatively instead of hanging.
- **`Assert.ThrowsExactlyAsync`** — use instead of `[ExpectedException]`; lets you inspect the exception and keeps the "act" line precise.
- **Fake `HttpMessageHandler`** — avoids real HTTP calls; the `DelayedHttpMessageHandler` simulates slow servers to test cancellation/timeout paths.
- **Sealed classes** and **constructor-injected `TestContext`** follow current MSTest 3.x+ conventions.
